INSERT INTO support_message (
    session_id, sender_scope, sender_id, message_type, content,
    attachment_path, attachment_name, attachment_content_type, attachment_size, created_at
) VALUES (
    #{sessionId}, #{senderScope}, #{senderId}, #{messageType}, #{content},
    #{attachmentPath}, #{attachmentName}, #{attachmentContentType}, #{attachmentSize}, #{createdAt}
)

mapper.select:
SELECT 
FROM support_message
WHERE session_id = #{sessionId}

    AND (
        created_at < #{cursorCreatedAt}
        OR (created_at = #{cursorCreatedAt} AND id < #{cursorId})
    )

ORDER BY created_at DESC, id DESC
LIMIT #{limit}

SELECT 
FROM support_message
WHERE session_id = #{sessionId}

    AND (
        created_at > #{afterCreatedAt}
        OR (created_at = #{afterCreatedAt} AND id > #{afterId})
    )

ORDER BY created_at ASC, id ASC
LIMIT #{limit}
